import{_ as t,c as o,o as a,ai as n}from"./chunks/framework.DUbA5Umu.js";const m=JSON.parse('{"title":"NeoNephos July Recap 2025","description":"","frontmatter":{"title":"NeoNephos July Recap 2025","date":"2025-08-01","banner":"assets/blog/20250801_neonephos_newsletter_july_recap_banner.jpg","authors":["esther-garcia"],"tags":["2025","newsletter"],"published":true,"sidebar":false,"aside":false,"prev":false,"next":false,"layout":"BlogEntryThemeComponent"},"headers":[],"relativePath":"blog/20250801_neonephos_newsletter.md","filePath":"blog/20250801_neonephos_newsletter.md"}'),r={name:"blog/20250801_neonephos_newsletter.md"};function i(s,e,l,h,u,p){return a(),o("div",null,e[0]||(e[0]=[n('<h1 id="neonephos-newsletter-july" tabindex="-1">NeoNephos Newsletter July <a class="header-anchor" href="#neonephos-newsletter-july" aria-label="Permalink to &quot;NeoNephos Newsletter  July&quot;">​</a></h1><p>Hello NeoNephos Newsletter readers! 👋</p><p>July has come to a pass. Let’s recap all the important things that happened in July:</p><h2 id="🛠️-tac-formed" tabindex="-1">🛠️ TAC formed <a class="header-anchor" href="#🛠️-tac-formed" aria-label="Permalink to &quot;🛠️ TAC formed&quot;">​</a></h2><p>On the 18th of July we held the kickoff meeting of our Technical Advisory Council (TAC), officially initiating this very important organizational body. The TAC ensures the technical adherence of the projects to the vision laid out by our Governing Board. The TAC will be spearheaded by the interim chairperson Florian Müller, who will reside in this position for the next three months.</p><h2 id="📣-first-neonephos-town-hall-held" tabindex="-1">📣 First NeoNephos Town Hall held <a class="header-anchor" href="#📣-first-neonephos-town-hall-held" aria-label="Permalink to &quot;📣 First NeoNephos Town Hall held&quot;">​</a></h2><p>On July 3rd we held our first townhall, inviting all the foundational members to participate. We got to know each other and discussed the timeline of important roadmap items, like the election of a General Member Governing Board Representative. It was a lively discussion and a lot of great ideas were exchanged.</p><h2 id="☁️-neonephos-at-cloudland-2025" tabindex="-1">☁️ NeoNephos at CloudLand 2025 <a class="header-anchor" href="#☁️-neonephos-at-cloudland-2025" aria-label="Permalink to &quot;☁️ NeoNephos at CloudLand 2025&quot;">​</a></h2><p>In the week starting July 1st we were present at the <a href="https://meine.doag.org/events/cloudland/2025/agenda/#agendaId.5686#eventDay.1751407200" target="_blank" rel="noreferrer">CloudLand 2025</a> with multiple talks featuring our projects. We outlined our holistic approach to a sovereign stack and encountered genuine interest in our focus areas. We were positively surprised by how many attendees already knew about some of our projects. Recordings can be accessed <a href="https://www.cloudland.org/en/archive/cloudland-2025/" target="_blank" rel="noreferrer">here</a>. It was a great week and we are thankful for the opportunity!</p><h2 id="☁️-neonephos-at-the-cloud-native-summit-in-munich" tabindex="-1">☁️ NeoNephos at the Cloud Native Summit in Munich <a class="header-anchor" href="#☁️-neonephos-at-the-cloud-native-summit-in-munich" aria-label="Permalink to &quot;☁️ NeoNephos at the Cloud Native Summit in Munich&quot;">​</a></h2><p>On July 21st Steffen Kelch from our Open Component Model project <a href="https://cloudnativesummit.de/schedule/" target="_blank" rel="noreferrer">held a talk</a> at the Cloud Native Summit Munich! See the recording <a href="https://www.youtube.com/watch?v=cIZ90x7aNJE&amp;list=PL54A_DPe8WtDLSA_EA7ETfprpRWzd2yqV&amp;index=12" target="_blank" rel="noreferrer">here</a>.</p><h2 id="🌎-neonephos-at-the-linux-foundation-europe-open-source-summit" tabindex="-1">🌎 NeoNephos at the Linux Foundation Europe Open Source Summit <a class="header-anchor" href="#🌎-neonephos-at-the-linux-foundation-europe-open-source-summit" aria-label="Permalink to &quot;🌎 NeoNephos at the Linux Foundation Europe Open Source Summit&quot;">​</a></h2><p>We will be present at the Linux Foundation Europe Open Source Summits with talks, panel discussions, merchandise and more! Register <a href="https://events.linuxfoundation.org/open-source-summit-europe/?utm_source=google&amp;utm_medium=paid-search&amp;utm_campaign=8235076-open-source-summit-europe-2025&amp;utm_term=events-osseu-2025-search-lf&amp;utm_content=events-osseu-2025-search-lf-rsa&amp;gad_source=1&amp;gad_campaignid=22830826258&amp;gclid=CjwKCAjwqKzEBhANEiwAeQaPVTeBo5ogo7BVZyE9Y1q7OZ8G0rHiei8AxzyAuXaNAW7mfi13gYpsKRoC7_oQAvD_BwE" target="_blank" rel="noreferrer">here</a> and use the discount code OSSEU25NEO for 20% off the Attendee registration rate.🎫</p><h2 id="📅-upcoming-community-call-–-september-10th" tabindex="-1">📅 Upcoming Community Call – September 10th <a class="header-anchor" href="#📅-upcoming-community-call-–-september-10th" aria-label="Permalink to &quot;📅 Upcoming Community Call – September 10th&quot;">​</a></h2><p>Don’t miss our next Community Call on Wednesday, September 10th at 4:00pm CEST.</p><p>🔗 <em>Join the call <a href="https://zoom-lfx.platform.linuxfoundation.org/meeting/94702324134?password=a3022011-25cd-44f3-b482-0ff389675eee" target="_blank" rel="noreferrer">here</a>.</em></p><p>This sums up our rundown for July. But the future looks even brigther, with new member announcements and more!</p><p><strong>Stay tuned: Exciting things ahead!</strong></p><p>The NeoNephos Foundation</p>',19)]))}const c=t(r,[["render",i]]);export{m as __pageData,c as default};
